CREATE TABLE writeups (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), slug citext NOT NULL UNIQUE, author_id uuid NOT NULL REFERENCES users(id), challenge_id uuid NOT NULL REFERENCES challenges(id), competition_id uuid REFERENCES competitions(id), title text NOT NULL, summary text NOT NULL DEFAULT '', content_markdown text NOT NULL DEFAULT '', content_html text NOT NULL DEFAULT '', status text NOT NULL DEFAULT 'draft' CHECK(status IN ('draft','review','published','rejected','archived')), visibility text NOT NULL DEFAULT 'public', reject_reason text NOT NULL DEFAULT '', featured boolean NOT NULL DEFAULT false, published_at timestamptz, opens_at timestamptz, views bigint NOT NULL DEFAULT 0, likes bigint NOT NULL DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE writeup_revisions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), writeup_id uuid NOT NULL REFERENCES writeups(id) ON DELETE CASCADE, version int NOT NULL, content_markdown text NOT NULL, created_by uuid NOT NULL REFERENCES users(id), created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(writeup_id,version));
CREATE TABLE writeup_comments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), writeup_id uuid NOT NULL REFERENCES writeups(id) ON DELETE CASCADE, user_id uuid NOT NULL REFERENCES users(id), content text NOT NULL, status text NOT NULL DEFAULT 'visible', created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE writeup_likes (writeup_id uuid REFERENCES writeups(id) ON DELETE CASCADE, user_id uuid REFERENCES users(id) ON DELETE CASCADE, created_at timestamptz NOT NULL DEFAULT now(), PRIMARY KEY(writeup_id,user_id));
CREATE TABLE writeup_favorites (writeup_id uuid REFERENCES writeups(id) ON DELETE CASCADE, user_id uuid REFERENCES users(id) ON DELETE CASCADE, created_at timestamptz NOT NULL DEFAULT now(), PRIMARY KEY(writeup_id,user_id));
CREATE TABLE writeup_reports (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), writeup_id uuid NOT NULL REFERENCES writeups(id), reporter_id uuid NOT NULL REFERENCES users(id), reason text NOT NULL, status text NOT NULL DEFAULT 'pending', created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE writeup_review_logs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), writeup_id uuid NOT NULL REFERENCES writeups(id), reviewer_id uuid NOT NULL REFERENCES users(id), action text NOT NULL, note text NOT NULL DEFAULT '', created_at timestamptz NOT NULL DEFAULT now());

CREATE TABLE asset_categories (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), key text NOT NULL UNIQUE, name text NOT NULL, description text NOT NULL DEFAULT '', created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE asset_tags (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name citext NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE assets (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), asset_key text NOT NULL UNIQUE, name text NOT NULL, category_id uuid REFERENCES asset_categories(id), alt_text text NOT NULL, status text NOT NULL DEFAULT 'draft' CHECK(status IN ('draft','published','archived')), fit text NOT NULL DEFAULT 'contain', position text NOT NULL DEFAULT 'center', focal_point jsonb NOT NULL DEFAULT '{"x":50,"y":50}', safe_area jsonb NOT NULL DEFAULT '{"top":8,"right":8,"bottom":8,"left":8}', applicable_pages jsonb NOT NULL DEFAULT '[]', fallback_asset_key text, current_version int NOT NULL DEFAULT 1, created_by uuid REFERENCES users(id), created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE asset_versions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), asset_id uuid NOT NULL REFERENCES assets(id) ON DELETE RESTRICT, version int NOT NULL, object_key text NOT NULL, public_url text NOT NULL DEFAULT '', mobile_object_key text, dark_object_key text, dark_mobile_object_key text, mime_type text NOT NULL, width int NOT NULL, height int NOT NULL, has_alpha boolean NOT NULL, sha256 text NOT NULL, risk_flags jsonb NOT NULL DEFAULT '[]', note text NOT NULL DEFAULT '', created_by uuid REFERENCES users(id), created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(asset_id,version));
CREATE INDEX asset_versions_sha_idx ON asset_versions(sha256);
CREATE TABLE asset_tag_links (asset_id uuid REFERENCES assets(id) ON DELETE CASCADE, tag_id uuid REFERENCES asset_tags(id) ON DELETE CASCADE, PRIMARY KEY(asset_id,tag_id));
CREATE TABLE asset_slots (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), slot_key text NOT NULL UNIQUE, name text NOT NULL, page_key text NOT NULL, fit text NOT NULL DEFAULT 'contain', position text NOT NULL DEFAULT 'center', enabled boolean NOT NULL DEFAULT true, version int NOT NULL DEFAULT 1, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE asset_bindings (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), slot_id uuid NOT NULL REFERENCES asset_slots(id), scope_type text NOT NULL DEFAULT 'platform', scope_id uuid, light_desktop_version_id uuid REFERENCES asset_versions(id), light_mobile_version_id uuid REFERENCES asset_versions(id), dark_desktop_version_id uuid REFERENCES asset_versions(id), dark_mobile_version_id uuid REFERENCES asset_versions(id), starts_at timestamptz, ends_at timestamptz, priority int NOT NULL DEFAULT 0, status text NOT NULL DEFAULT 'draft', created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE asset_usage_records (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), asset_version_id uuid NOT NULL REFERENCES asset_versions(id), resource_type text NOT NULL, resource_id uuid, slot_key text NOT NULL DEFAULT '', historical boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE asset_processing_jobs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), asset_version_id uuid NOT NULL REFERENCES asset_versions(id), status text NOT NULL DEFAULT 'queued', result jsonb NOT NULL DEFAULT '{}', error_code text NOT NULL DEFAULT '', created_at timestamptz NOT NULL DEFAULT now(), finished_at timestamptz);

CREATE TABLE themes (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), theme_key text NOT NULL UNIQUE, name text NOT NULL, status text NOT NULL DEFAULT 'draft', current_version int NOT NULL DEFAULT 1, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE theme_versions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), theme_id uuid NOT NULL REFERENCES themes(id), version int NOT NULL, tokens jsonb NOT NULL, created_by uuid REFERENCES users(id), created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(theme_id,version));
CREATE TABLE theme_bindings (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), theme_version_id uuid NOT NULL REFERENCES theme_versions(id), scope_type text NOT NULL, scope_id uuid, starts_at timestamptz, ends_at timestamptz, priority int NOT NULL DEFAULT 0, status text NOT NULL DEFAULT 'draft');
CREATE TABLE page_background_configs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), page_key text NOT NULL, scope_type text NOT NULL DEFAULT 'platform', scope_id uuid, light_asset_key text NOT NULL, dark_asset_key text, mobile_asset_key text, dark_mobile_asset_key text, fit text NOT NULL DEFAULT 'cover', position text NOT NULL DEFAULT 'center', focal_point jsonb NOT NULL DEFAULT '{"x":50,"y":50}', overlay_color text NOT NULL DEFAULT '#ffffff', overlay_opacity int NOT NULL DEFAULT 70 CHECK(overlay_opacity BETWEEN 0 AND 100), asset_opacity int NOT NULL DEFAULT 15 CHECK(asset_opacity BETWEEN 0 AND 100), blur int NOT NULL DEFAULT 0, starts_at timestamptz, ends_at timestamptz, status text NOT NULL DEFAULT 'draft', version int NOT NULL DEFAULT 1, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE competition_appearance (competition_id uuid PRIMARY KEY REFERENCES competitions(id) ON DELETE CASCADE, theme_version_id uuid REFERENCES theme_versions(id), banner_asset_key text NOT NULL DEFAULT '', trophy_asset_key text NOT NULL DEFAULT '', medal_asset_key text NOT NULL DEFAULT '', background_config jsonb NOT NULL DEFAULT '{}', updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE appearance_preview_tokens (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), subject_type text NOT NULL, subject_id uuid NOT NULL, token_hash text NOT NULL UNIQUE, expires_at timestamptz NOT NULL, created_by uuid NOT NULL REFERENCES users(id));

CREATE TABLE level_schemes (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), key text NOT NULL UNIQUE, name text NOT NULL, scope_type text NOT NULL DEFAULT 'platform', enabled boolean NOT NULL DEFAULT true, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE level_tiers (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), scheme_id uuid NOT NULL REFERENCES level_schemes(id) ON DELETE CASCADE, key text NOT NULL, name text NOT NULL, min_experience bigint NOT NULL, max_experience bigint, sort_order int NOT NULL, badge_asset_key text NOT NULL, small_badge_asset_key text NOT NULL DEFAULT '', frame_asset_key text NOT NULL DEFAULT '', color text NOT NULL DEFAULT '#1677ff', gradient text NOT NULL DEFAULT '', UNIQUE(scheme_id,key));
CREATE TABLE experience_rules (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), scheme_id uuid NOT NULL REFERENCES level_schemes(id), event_type text NOT NULL, amount int NOT NULL, daily_cap int, weekly_cap int, enabled boolean NOT NULL DEFAULT true, UNIQUE(scheme_id,event_type));
CREATE TABLE user_experience (user_id uuid NOT NULL REFERENCES users(id), scheme_id uuid NOT NULL REFERENCES level_schemes(id), experience bigint NOT NULL DEFAULT 0, tier_id uuid REFERENCES level_tiers(id), updated_at timestamptz NOT NULL DEFAULT now(), PRIMARY KEY(user_id,scheme_id));
CREATE TABLE experience_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id), scheme_id uuid NOT NULL REFERENCES level_schemes(id), type text NOT NULL, delta int NOT NULL, reference_type text NOT NULL, reference_id uuid NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(user_id,scheme_id,type,reference_type,reference_id));
CREATE TABLE medals (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), key text NOT NULL UNIQUE, name text NOT NULL, description text NOT NULL DEFAULT '', rarity text NOT NULL, unlocked_asset_key text NOT NULL, locked_asset_key text NOT NULL, enabled boolean NOT NULL DEFAULT true);
CREATE TABLE medal_rules (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), medal_id uuid NOT NULL REFERENCES medals(id), event_type text NOT NULL, config jsonb NOT NULL DEFAULT '{}', enabled boolean NOT NULL DEFAULT true);
CREATE TABLE user_medals (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id), medal_id uuid NOT NULL REFERENCES medals(id), source_type text NOT NULL, source_id uuid, asset_version_id uuid REFERENCES asset_versions(id), awarded_at timestamptz NOT NULL DEFAULT now(), revoked_at timestamptz, UNIQUE(user_id,medal_id,source_type,source_id));
CREATE TABLE team_medals (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), team_id uuid NOT NULL REFERENCES teams(id), medal_id uuid NOT NULL REFERENCES medals(id), source_type text NOT NULL, source_id uuid, asset_version_id uuid REFERENCES asset_versions(id), awarded_at timestamptz NOT NULL DEFAULT now(), revoked_at timestamptz, UNIQUE(team_id,medal_id,source_type,source_id));
CREATE TABLE competition_rewards (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), competition_id uuid NOT NULL REFERENCES competitions(id), reward_type text NOT NULL, rank_from int, rank_to int, config jsonb NOT NULL DEFAULT '{}', enabled boolean NOT NULL DEFAULT true);
CREATE TABLE reward_distribution_runs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), competition_id uuid NOT NULL REFERENCES competitions(id), snapshot_id uuid NOT NULL REFERENCES scoreboard_snapshots(id), status text NOT NULL, started_by uuid REFERENCES users(id), started_at timestamptz NOT NULL DEFAULT now(), finished_at timestamptz, UNIQUE(competition_id,snapshot_id));

CREATE TABLE notifications (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id), type text NOT NULL, title text NOT NULL, body text NOT NULL, link text NOT NULL DEFAULT '', payload jsonb NOT NULL DEFAULT '{}', read_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX notifications_user_idx ON notifications(user_id,read_at,created_at DESC);
CREATE TABLE notification_deliveries (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), notification_id uuid NOT NULL REFERENCES notifications(id) ON DELETE CASCADE, channel text NOT NULL, status text NOT NULL DEFAULT 'pending', attempts int NOT NULL DEFAULT 0, delivered_at timestamptz, last_error text NOT NULL DEFAULT '');
CREATE TABLE announcements (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), type text NOT NULL, title text NOT NULL, content text NOT NULL, status text NOT NULL DEFAULT 'draft', starts_at timestamptz, ends_at timestamptz, created_by uuid NOT NULL REFERENCES users(id), created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE user_announcement_reads (announcement_id uuid REFERENCES announcements(id) ON DELETE CASCADE, user_id uuid REFERENCES users(id) ON DELETE CASCADE, read_at timestamptz NOT NULL DEFAULT now(), PRIMARY KEY(announcement_id,user_id));
CREATE TABLE cheat_rules (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), key text NOT NULL UNIQUE, name text NOT NULL, config jsonb NOT NULL DEFAULT '{}', risk_score int NOT NULL, enabled boolean NOT NULL DEFAULT true);
CREATE TABLE cheat_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), rule_id uuid REFERENCES cheat_rules(id), user_id uuid REFERENCES users(id), team_id uuid REFERENCES teams(id), risk_score int NOT NULL, evidence jsonb NOT NULL, request_id text NOT NULL DEFAULT '', created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE cheat_cases (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), status text NOT NULL DEFAULT 'open', risk_level text NOT NULL, assignee_id uuid REFERENCES users(id), resolution text NOT NULL DEFAULT '', created_at timestamptz NOT NULL DEFAULT now(), closed_at timestamptz);
CREATE TABLE cheat_case_notes (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), case_id uuid NOT NULL REFERENCES cheat_cases(id) ON DELETE CASCADE, author_id uuid NOT NULL REFERENCES users(id), content text NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE suspicious_submissions (case_id uuid REFERENCES cheat_cases(id) ON DELETE CASCADE, submission_id uuid REFERENCES submissions(id) ON DELETE CASCADE, PRIMARY KEY(case_id,submission_id));
CREATE TABLE audit_logs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), actor_id uuid REFERENCES users(id), actor_type text NOT NULL, action text NOT NULL, resource_type text NOT NULL, resource_id text NOT NULL, before_json jsonb, after_json jsonb, ip inet, user_agent text NOT NULL DEFAULT '', request_id text NOT NULL DEFAULT '', created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX audit_logs_resource_idx ON audit_logs(resource_type,resource_id,created_at DESC);
CREATE TABLE outbox_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), aggregate_type text NOT NULL, aggregate_id uuid NOT NULL, event_type text NOT NULL, payload jsonb NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), published_at timestamptz, attempts int NOT NULL DEFAULT 0, last_error text NOT NULL DEFAULT '');

