DROP TABLE IF EXISTS outbox_events,audit_logs,suspicious_submissions,cheat_case_notes,cheat_cases,cheat_events,cheat_rules,user_announcement_reads,announcements,notification_deliveries,notifications,reward_distribution_runs,competition_rewards,team_medals,user_medals,medal_rules,medals,experience_events,user_experience,experience_rules,level_tiers,level_schemes,appearance_preview_tokens,competition_appearance,page_background_configs,theme_bindings,theme_versions,themes,asset_processing_jobs,asset_usage_records,asset_bindings,asset_slots,asset_tag_links,asset_versions,assets,asset_tags,asset_categories,writeup_review_logs,writeup_reports,writeup_favorites,writeup_likes,writeup_comments,writeup_revisions,writeups CASCADE;
